// Build a formatted order summary from the webhook payload
const payload = $input.first().json.body;
const data = payload.data;

const itemLines = (data.items || [])
  .map(i => `  - ${i.name} (x${i.qty}) $${(i.price * i.qty).toFixed(2)}${i.variant ? ' [' + i.variant + ']' : ''}`)
  .join('\n');

const statusLabel = (data.status || 'pending').replace(/_/g, ' ').toUpperCase();
const payMethod = (data.paymentMethod || 'card').toUpperCase();

const text = `
🛍️ *NEW ORDER* #${data.orderNumber}
━━━━━━━━━━━━━━━━━━━━

👤 *Customer:* ${data.customerName}
📧 *Email:* ${data.email}
${data.phone ? '📱 *Phone:* ' + data.phone + '\n' : ''}
💰 *Total:* $${data.total.toFixed(2)}
💳 *Payment:* ${payMethod}
📋 *Status:* ${statusLabel}

📦 *Items:*
${itemLines}

📍 *Shipping:*
  ${data.shippingAddress.firstName} ${data.shippingAddress.lastName}
  ${data.shippingAddress.address}
  ${data.shippingAddress.city}, ${data.shippingAddress.postal}
  ${data.shippingAddress.country}

🔗 *Admin:* https://luxe-ruby-delta.vercel.app/admin/orders/${data.orderId}
⏰ *Time:* ${payload.timestamp}
`;

return [{ json: { ...data, formattedText: text, orderNumber: data.orderNumber } }];
